1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type Damage = { itemType: string; amount: number };
5	type ClaimStep = {
6	  op: "claim";
7	  policy: number;
8	  incident: { cause: string; damages: Damage[] };
9	};
10	type Step = QuoteStep | ClaimStep;
11	
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	type QuoteResult = { premium: number };
14	type ClaimResult = { payout: number };
15	type Result = QuoteResult | ClaimResult;
16	
17	const PROCESSING_FEE = 5;
18	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
19	const CURSE_SURCHARGE_RATE = 0.5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const LOYALTY_YEARS_THRESHOLD = 2;
24	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
25	const DEDUCTIBLE_PER_DAMAGE = 100;
26	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	
29	const BASE_PREMIUM: Record<string, number> = {
30	  sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25,
31	};
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const BLOCK_SIZE = 3;
34	const BLOCK_BASE_PREMIUM = 60;
35	
36	const sum = (numbers: number[]): number => numbers.reduce((a, b) => a + b, 0);
37	
38	const baseForItem = (item: Item): number => BASE_PREMIUM[item.type];
39	
40	const baseForComponentGroup = (count: number): number =>
41	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM.rune;
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const list = groups.get(item.type) ?? [];
47	    list.push(item);
48	    groups.set(item.type, list);
49	  }
50	  return groups;
51	};
52	
53	const totalBaseForItems = (items: Item[]): number => {
54	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
55	  const componentItems = items.filter((i) => COMPONENT_TYPES.has(i.type));
56	  const mainBase = sum(mainItems.map(baseForItem));
57	  const componentGroups = groupByType(componentItems);
58	  const componentBase = sum(
59	    Array.from(componentGroups.values()).map((group) => baseForComponentGroup(group.length)),
60	  );
61	  return mainBase + componentBase;
62	};
63	
64	const itemSurcharges = (item: Item): number => {
65	  const base = BASE_PREMIUM[item.type];
66	  let surcharge = 0;
67	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
68	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
69	  return surcharge;
70	};
71	
72	const computePremium = (items: Item[], isLoyal: boolean, isFollowUp: boolean): number => {
73	  for (const item of items) {
74	    if (!(item.type in BASE_PREMIUM)) {
75	      throw new Error(`Unknown item type: ${item.type}`);
76	    }
77	  }
78	  const baseTotal = totalBaseForItems(items);
79	  const surchargesTotal = sum(items.map(itemSurcharges));
80	  const firstInsuranceTotal = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
81	  const loyaltyDiscount = isLoyal ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
82	  const followUpDiscount = isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
83	  const total = baseTotal + surchargesTotal + firstInsuranceTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
84	  return Math.ceil(total);
85	};
86	
87	const payoutForDamage = (damage: Damage, item: Item): number => {
88	  const isHighEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
89	  const reimbursable = isHighEnchantment
90	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
91	    : damage.amount;
92	  return reimbursable - DEDUCTIBLE_PER_DAMAGE;
93	};
94	
95	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
96	  const counts = new Map<string, number>();
97	  for (const item of items) {
98	    const key = keyOf(item);
99	    counts.set(key, (counts.get(key) ?? 0) + 1);
100	  }
101	  return counts;
102	};
103	
104	const computePayout = (damages: Damage[], policyItems: Item[]): number => {
105	  for (const d of damages) {
106	    if (d.amount < 0) {
107	      throw new Error(`Damage amount must be non-negative, got ${d.amount}`);
108	    }
109	  }
110	  const damageCounts = countBy(damages, (d) => d.itemType);
111	  const policyCounts = countBy(policyItems, (i) => i.type);
112	  for (const [type, count] of damageCounts) {
113	    if (count > (policyCounts.get(type) ?? 0)) {
114	      throw new Error(`Claim has more ${type} damages than insured`);
115	    }
116	  }
117	  const total = sum(
118	    damages.map((d) => {
119	      const item = policyItems.find((i) => i.type === d.itemType);
120	      return payoutForDamage(d, item ?? { type: d.itemType });
121	    }),
122	  );
123	  return Math.floor(total);
124	};
125	
126	export const runScenario = (scenario: Scenario): { results: Result[] } => {
127	  const isLoyal = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
128	  let quoteCount = 0;
129	  const results: Result[] = scenario.steps.map((step) => {
130	    if (step.op === "quote") {
131	      const isFollowUp = quoteCount > 0;
132	      quoteCount += 1;
133	      return { premium: computePremium(step.items, isLoyal, isFollowUp) };
134	    }
135	    const policyStep = scenario.steps[step.policy];
136	    const policyItems = policyStep.op === "quote" ? policyStep.items : [];
137	    return { payout: computePayout(step.incident.damages, policyItems) };
138	  });
139	  return { results };
140	};
